if &erroMensagem.IsEmpty()
	For Each Order tmpNFeCod //CAPA
		where tmpNFeCod = &tmpNFeCod

		//		If tmpNfeFin = NotaFinalidade.EmissaoDevolucao and (tmpNfeChvRef.IsEmpty() or tmpNfeChvRef.Length() < 44) //Valida Nota Devolucao 
		//			&erroMensagem = &erroMensagem.Trim() + newLine() + ' Para Notas de devolução obrigatóriamente deve-se informar a chave da Nota Fiscal que originou a Devolução!'
		//		EndIF
		//		
		//		If (&PedCliEntUfeCod = 'EX' and tmpExpCidCod.IsEmpty()) and &LctAtuSal = Status_EntradaSaida.Saida
		//			&erroMensagem = &erroMensagem.Trim() + newLine() + ' Para Notas de Exportação é preciso informar o Local de Embarque!'
		//		EndIF
		//		
		//		If (not tmpNfeEspVol.IsEmpty() and tmpNfeQtdVol = 0) or (tmpNfeEspVol.IsEmpty() and tmpNfeQtdVol <> 0)
		//			&erroMensagem = &erroMensagem.Trim() + newLine() + ' Ao informar a Espécie do volume é preciso informar a quantidade de volumes e vice-versa!'
		//		EndIF

		if not &erroMensagem.IsEmpty()
			Return
		EndiF

		For Each order tmpNFeCod, tmpNfeItmCod //ITEM
			Where tmpPedQtdFat > 0

			&tmpPedVlrTotNov += tmpPedVlrTotNov
			//PRODUTO
	    	If (tmpNcmCod < 100 or (tmpNcmCod > 99 and tmpNcmCod < 999999))
		        &erroMensagem = &erroMensagem.Trim() + newLine() + ' Produto: ' + trim(tmpProRef) + ' - NCM inválido!'
		    EndIf

			&FilBasImp = retornaFilialBaseImposto.UDP(tmpEmpCod, tmpNfeFatFilCod)
			&erroCFOPMensagem = validaCfopTabelaImposto.UDP(tmpEmpCod, &FilBasImp, &LctbasImpCod, &PedCliEntUfeCod, tmpCFOP)
			If not &erroCFOPMensagem.IsEmpty()
				&erroMensagem = &erroMensagem.Trim() + newLine() + &erroCFOPMensagem.Trim()
			EndIF

			&SoNumeros = RetornaSoNumeros.Udp(tmpNfeSitCod)
			&SitCod = val(&SoNumeros)
			&ErroCSTMensagem = validaSituacaoTributaria.Udp(tmpEmpCod, &FilBasImp, &SitCod)
			if not &ErroCSTMensagem.IsEmpty()
				&erroMensagem = &erroMensagem.Trim() + newLine() + &ErroCSTMensagem.Trim()
			EndIF

			If tmpCFOP.IsEmpty()
				&erroMensagem = &erroMensagem.Trim() + newLine() + ' Verifique Tabela de Imposto Produto:' + trim(tmpProRef)
			EndIF

			if not &erroMensagem.IsEmpty()
				Return
			EndiF

		EndFor
	EndFor
EndIf

if &tmpPedVlrTotNov <= 0
	&erroMensagem =  &erroMensagem.Trim() + newLine() + ' Não Produtos nesse pedido para emitir Nota Fiscal'
	Return
Endif
